import React, { FC } from 'react';
import './HeroBanner.scss';
import { Button } from ':components/Button';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { HeroBannerAction, HeroBannerProps } from './HeroBanner.types';

export const HeroBanner: FC<HeroBannerProps> = ({
	header,
	headline,
	imagePosition = 'absolute',
	image,
	actions,
	renderAction,
	onAction,
	dataTestId = 'HeroBanner',
	className,
	imageAlt,
	...rest
}) => {
	const base = 'dsb_herobanner';

	const handleClick = (action: HeroBannerAction) => () => {
		onAction?.(action);
	};

	const renderImage = () => {
		if (!image) return null;
		return (
			<>
				{typeof image === 'string' ? (
					<img className={classNames(`${base}__image`, `${base}__image-${imagePosition}`)} src={image} alt={imageAlt} />
				) : (
					image
				)}
			</>
		);
	};

	const renderActions = () => {
		if (!actions?.length) return null;

		return (
			<div className={`${base}__actions`}>
				{actions.map(a =>
					renderAction ? (
						<React.Fragment>{renderAction(a, handleClick(a))}</React.Fragment>
					) : (
						<Button
							href={a.href}
							size={'medium'}
							variant={a.primary ? 'contained' : 'outlined'}
							onClick={handleClick(a)}
							disabled={a.disabled}
							aria-label={a['aria-label']}
						>
							{a.label}
						</Button>
					),
				)}
			</div>
		);
	};

	return (
		<div className={classNames(base, className)} data-testId={dataTestId} role="banner" {...rest}>
			<div className={`${base}-content`}>
				{header && (
					<Typography variant="h1" className={`${base}__header`}>
						{header}
					</Typography>
				)}
				{headline && (
					<Typography variant="body1" inactive className={`${base}__headline`}>
						{headline}
					</Typography>
				)}
				{renderActions()}
			</div>

			{renderImage()}
		</div>
	);
};

export default HeroBanner;
